def test_mobile_cheque_deposit_invalid_micr_returns_422(auth_session, corrupt_micr_image):
    idempotency_key = <generate_uuid>()
    payload = {
        "amount": 500,
        "currency": "USD",
        "image": corrupt_micr_image,
    }
    headers = {
        "Authorization": f"Bearer {auth_session.token}",
        "Idempotency-Key": idempotency_key,
    }
    resp = <api_client>.post("/deposits/mobile-cheque", json=payload, headers=headers)
    assert resp.status_code == 422
    body = resp.json()
    assert "MICR_DECODE" in body.get("error_code", "").upper() or \
           "micr" in body.get("message", "").lower()
